function fb(a, b) { if (a) { return a; } return b; }
var task = fb($.input.taskDescription, '');
var constraints = fb($.input.constraints, '');

var prompt = 'You are an automation architect and workflow design expert. Design a complete, production-ready automation workflow for the following task.\n\n';
prompt += 'TASK: ' + task + '\n';
if (constraints) prompt += 'CONSTRAINTS: ' + constraints + '\n';
prompt += '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Design a step-by-step workflow\n';
prompt += '- Recommend specific tools and integrations\n';
prompt += '- Include error handling and edge cases\n';
prompt += '- Estimate complexity and implementation time\n';
prompt += '- Note any prerequisites or setup needed\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "workflowName": "descriptive name",\n';
prompt += '  "summary": "2-3 sentence overview of the automation",\n';
prompt += '  "trigger": { "type": "how the workflow starts", "details": "specifics" },\n';
prompt += '  "steps": [\n';
prompt += '    { "order": 1, "name": "step name", "tool": "tool or service", "action": "what it does", "inputsNeeded": ["input 1"], "outputsProduced": ["output 1"], "errorHandling": "what to do on failure" }\n';
prompt += '  ],\n';
prompt += '  "integrations": [{ "name": "tool name", "purpose": "why its needed", "alternatives": ["alt 1"] }],\n';
prompt += '  "errorHandling": { "strategy": "overall strategy", "retryPolicy": "description", "notifications": "how to alert on failure" },\n';
prompt += '  "complexity": "simple/moderate/complex",\n';
prompt += '  "estimatedBuildTime": "time to implement",\n';
prompt += '  "prerequisites": ["prereq 1"],\n';
prompt += '  "tips": ["implementation tip 1"]\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiDesign.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { workflowName: 'Custom Workflow', summary: raw, steps: [], integrations: [] }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':gear: Workflow Blueprint: ' + (fb(ai.workflowName, 'Custom Workflow')), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fb(ai.summary, 'Workflow designed.') } });

var complexityIcon = ':large_green_circle:';
if (ai.complexity === 'moderate') complexityIcon = ':large_orange_circle:';
if (ai.complexity === 'complex') complexityIcon = ':red_circle:';

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: complexityIcon + ' *Complexity:* ' + (fb(ai.complexity, 'N/A')) + '  |  :clock1: *Build Time:* ' + (fb(ai.estimatedBuildTime, 'N/A')) }] });
blocks.push({ type: 'divider' });

var trigger = fb(ai.trigger, {});
if (trigger.type) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':zap: *Trigger:* ' + trigger.type + '\n' + (fb(trigger.details, '')) } });
  blocks.push({ type: 'divider' });
}

var steps = fb(ai.steps, []);
if (steps.length > 0) {
  var stepsText = '*:clipboard: Workflow Steps*\n';
  steps.forEach(function(step) {
    stepsText += '*' + step.order + '. ' + step.name + '* (' + (fb(step.tool, 'N/A')) + ')\n';
    stepsText += '   ' + (fb(step.action, '')) + '\n';
    if (step.errorHandling) stepsText += '   _On error:_ ' + step.errorHandling + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: stepsText } });
}

var integrations = fb(ai.integrations, []);
if (integrations.length > 0) {
  blocks.push({ type: 'divider' });
  var intText = '*:link: Required Integrations*\n';
  integrations.forEach(function(intg) {
    intText += '- *' + intg.name + '*: ' + (fb(intg.purpose, ''));
    var alts = fb(intg.alternatives, []);
    if (alts.length > 0) intText += ' (alt: ' + alts.join(', ') + ')';
    intText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: intText } });
}

var prereqs = fb(ai.prerequisites, []);
if (prereqs.length > 0) {
  blocks.push({ type: 'divider' });
  var preText = '*:pushpin: Prerequisites*\n';
  prereqs.forEach(function(p, i) { preText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: preText } });
}

var tips = fb(ai.tips, []);
if (tips.length > 0) {
  var tipText = '*:bulb: Tips*\n';
  tips.forEach(function(t) { tipText += '- ' + t + '\n'; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: tipText }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + One CLI' }] });

var fallback = 'Workflow Blueprint: ' + (fb(ai.workflowName, 'Custom Workflow'));
return { blocks: blocks, fallback: fallback };
